        ...(event.team?.members
          ? event.team?.members.map((member) => ({
              emailAddress: {
                address: member.email,
                name: member.name,
              },
              type: "required",
            }))
          : []),
      ],
      location: event.location ? { displayName: getLocation(event) } : undefined,
    };
